package automation

import (
	"context"

	"google.golang.org/grpc"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/actor/automation"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/events"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type OnAccountDeleteProxy struct {
	automation.UnimplementedOnAccountDeleteServer
	client automation.OnAccountDeleteClient
}

func init() {
	proxyutil.Register(&automation.OnAccountDelete_ServiceDesc, NewOnAccountDeleteProxy)
}
func NewOnAccountDeleteProxy(cc grpc.ClientConnInterface) automation.OnAccountDeleteServer {
	return &OnAccountDeleteProxy{client: automation.NewOnAccountDeleteClient(cc)}
}
func (p *OnAccountDeleteProxy) OnAccountDelete(ctx context.Context, in *events.AccountDelete) (*automation.HandlerResult, error) {
	return proxyutil.ProxyMethod[events.AccountDelete, automation.HandlerResult](p.client.OnAccountDelete)(ctx, in)
}
